/**
 * Template for generating SQL migration files
 */

import { toTableName } from '../generators/utils.js';

export function generateMigrationTemplate(entityName: string): string {
  const tableName = toTableName(entityName);

  return `-- @generated by @flusk/cli from ${entityName}.entity.ts
-- DO NOT EDIT - regenerate using: flusk g ${entityName}.entity.ts

-- Create ${tableName} table
CREATE TABLE IF NOT EXISTS ${tableName} (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
  -- TODO: Add columns from entity schema
);

-- Create indexes
CREATE INDEX IF NOT EXISTS idx_${tableName}_created_at ON ${tableName}(created_at);
CREATE INDEX IF NOT EXISTS idx_${tableName}_updated_at ON ${tableName}(updated_at);

-- Create updated_at trigger
CREATE OR REPLACE FUNCTION update_${tableName}_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER ${tableName}_updated_at
  BEFORE UPDATE ON ${tableName}
  FOR EACH ROW
  EXECUTE FUNCTION update_${tableName}_updated_at();
`;
}
